CREATE TABLE IF NOT EXISTS user_timeline (internal_id INT, bio VARCHAR(1000) NULL, devlog_count INT NULL, project_count INT NULL, ship_count INT NULL, votes_count INT NULL, achievements_count INT NULL, follower_count INT NULL, following_count INT NULL, streak INT NULL, pages INT NULL, request INT, CONSTRAINT pk_user_timeline PRIMARY KEY (internal_id, request), CONSTRAINT fk_user_timeline_request__id FOREIGN KEY (request) REFERENCES requests(id) ON DELETE RESTRICT ON UPDATE RESTRICT);